VALUES
  ('social-worker-moex-07070', 'social-worker', 'social-worker-moex-101-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '李太太打電話給醫務社工師，表示患有失智症的公公常會覺得銀行的存款被家人領走了，有多疑、猜忌 的情形。社工師最合宜的處置為何？', '["教導李太太向公公說：「我們都在你身邊，沒有人拿你的錢。」", "傾聽李太太的訴說，並教導其失智症的相關症狀", "告知李太太多疑症狀是失智症病人常有的行為，不要理會，公公自然遺忘所猜忌之事", "鼓勵李太太帶公公去銀行提款，以矯治其妄想行為"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "0b336dc02022", "answer_pdf_sha1": "b9eb953e36b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07071', 'social-worker', 'social-worker-moex-101-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '孕婦長期抽菸對胎兒的影響是什麼？', '["造成長期性的肥胖與鉛中毒不良影響", "由於肺部長期碳化，引發唐氏症", "胎兒成長遲緩，增加流產或早產兒的機率", "直至目前對胎兒的研究並未顯示任何直接或間接作用"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "0b336dc02022", "answer_pdf_sha1": "b9eb953e36b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07072', 'social-worker', 'social-worker-moex-101-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '女性學者Gilligan批評柯柏格（Lawrence Kohlberg）的「道德認知發展理論」忽視性別差異的前提，以下 的敘述中，何者最不可能是Gilligan的論點？', '["道德認知發展的評量，應該考量男孩和女孩社會化的差別經驗", "道德認知發展的評量，應該考量以權利和責任相應的前提", "偏男性觀點的道德認知發展的評量，往往發現女性道德發展程度低於同年齡的男性", "女性的道德認知發展的評量，較適合考量以關懷他人福祉為中心來建構"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "0b336dc02022", "answer_pdf_sha1": "b9eb953e36b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07073', 'social-worker', 'social-worker-moex-101-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '對現代家庭特性的分析中，有所謂「飽和的家庭」（saturated family）和「流動的家庭」（floating family） 等概念被提出，下列敘述中，何者係這兩個概念所要指出之現代家庭的困境？', '["現代家庭普遍過度富裕、追逐過多慾望之滿足而欠缺寧靜和安定感", "現代家庭生活中，人們根本無法凝聚家庭目標共識，所謂的「好家庭」已不再具有意義", "現代家庭生活充滿瑣事、工作情況又充滿變數，使得家人易於分散各地", "現代家庭富裕有餘，真實地享受不足"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "0b336dc02022", "answer_pdf_sha1": "b9eb953e36b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07074', 'social-worker', 'social-worker-moex-101-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列何敘述，那一項最能說明來自非主流族群的學齡兒童在求學過程中，較容易發生認知不協調的狀況？', '["非主流族群學童由於語言差異，較不容易了解其他文化行為的意義所致", "非主流族群學童由於家庭社經地位偏低，較易受到不利的學習環境影響所致", "非主流族群學童由於膚色的差異，較易被偏見、歧視影響所致", "非主流族群學童由於自卑或欠缺自信，較易被邊緣化所致"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "0b336dc02022", "answer_pdf_sha1": "b9eb953e36b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07075', 'social-worker', 'social-worker-moex-101-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關安寧照顧（hospice）模式的敘述中，下列何者錯誤？', '["安寧照顧採團隊服務方式，其對象包括病人及其家屬", "安寧照顧提供生理、心理、社會及靈性層面需求方面的協助，但不再採取以治癒為目標之侵入式治療", "安寧照顧還針對喪親之痛的歷程提供家屬後續服務", "安寧照顧與傳統臨終治療唯一相同的，主要都在醫療院所中實施"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "0b336dc02022", "answer_pdf_sha1": "b9eb953e36b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07076', 'social-worker', 'social-worker-moex-101-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '「兒童會重複表現受到獎勵的行為，及避免會受到懲罰的行為，因此，父母對小孩行為回應的一致性非 常重要」，以上所述係基於何種理論觀點？', '["精神動力理論", "社會交換理論", "社會學習理論", "認知發展理論"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "0b336dc02022", "answer_pdf_sha1": "b9eb953e36b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07077', 'social-worker', 'social-worker-moex-101-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '依佛洛伊德（Sigmund Freud）的理論，人類自我的發展係歷經一系列性心理發展的階段。他所提出之性 心理發展的階段，若按先後順序排列，下列何者正確？', '["口腔期、肛門期、潛伏期、性蕾期（phallic stage）、性徵期（genital stage）", "肛門期、潛伏期、口腔期、性蕾期（phallic stage）、性徵期（genital stage）", "口腔期、肛門期、性蕾期（phallic stage）、潛伏期、性徵期（genital stage）", "口腔期、肛門期、性徵期（genital stage）、潛伏期、性蕾期（phallic stage）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "0b336dc02022", "answer_pdf_sha1": "b9eb953e36b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07078', 'social-worker', 'social-worker-moex-101-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '根據艾瑞克森（Eric H. Erickson）的心理社會發展理論，兒童早期（約3至5歲）的心理社會發展任務是：', '["發展自信及掌握自己的能力和克服自卑的危機", "發展主動、積極行動的能力和克服罪惡感的危機", "發展出與他人的信任關係和克服罪惡感的危機", "發展出勤奮達成任務的能力和克服自卑的危機"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "0b336dc02022", "answer_pdf_sha1": "b9eb953e36b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07079', 'social-worker', 'social-worker-moex-101-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關兒童早期攻擊行為的敘述下列何者錯誤？', '["比起年齡較大的兒童，2到3歲的兒童比較不會理會父母的勸阻而繼續攻擊性的行為", "遊戲時不小心打傷人的行為，是屬於工具性攻擊", "年小的兒童，較年長的兒童會為了得到想要的東西，表現出工具性攻擊的行為", "兒童雖然有傷害對方的意圖，但卻沒有達到傷害對方的攻擊行為，不能算是惡意攻擊"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "0b336dc02022", "answer_pdf_sha1": "b9eb953e36b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
